mapper.select:
SELECT R.RPT_NO AS rptNo, R.RPT_TYPE_CD AS rptTypeCd, R.RPT_REASON_CD AS rptReasonCd, R.RPT_REASON_CONTENT AS rptReasonContent, R.RPT_STATUS_CD AS rptStatusCd, R.RPT_REG_DATE AS rptRegDate, M.MBR_NICKNAME AS reporterName, COALESCE(R.RPT_REVIEW_NO, R.RPT_COMM_NO, R.RPT_CMNT_NO) AS targetId, C.COMM_CAT_CD AS reportedCategory, C.COMM_TITLE AS reportedTitle, COALESCE(RV.RVW_CONTENT, C.COMM_CONTENT, CM.CMNT_CONTENT) AS reportedContent FROM REPORT R JOIN MEMBER M ON R.RPT_REPORTER_NO = M.MBR_ID
LEFT JOIN REVIEW RV ON R.RPT_REVIEW_NO = RV.RVW_NO LEFT JOIN COMMUNITY C ON R.RPT_COMM_NO = C.COMM_NO LEFT JOIN COMMENT CM ON R.RPT_CMNT_NO = CM.CMNT_NO WHERE 1=1
ORDER BY R.RPT_REG_DATE DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM REPORT
WHERE RPT_REPORTER_NO = #{rptReporterNo}
  AND RPT_TYPE_CD = #{rptTypeCd}

  AND RPT_COMM_NO = #{rptCommNo}


  AND RPT_CMNT_NO = #{rptCmntNo}


  AND RPT_REVIEW_NO = #{rptReviewNo}

SELECT COUNT(*) 
FROM REPORT
WHERE RPT_TYPE_CD = #{rptTypeCd}
  AND RPT_STATUS_CD != 'RST004' /* 🚀 반려된 신고는 카운트에서 제외 */
 AND RPT_REVIEW_NO = #{rptReviewNo} 
 AND RPT_COMM_NO = #{rptCommNo} 
 AND RPT_CMNT_NO = #{rptCmntNo}
